app.listen(port, () => logger.info({ port }, 'listening'));
```

---

### 8. No body parser limits (Low, preventive)

When you add `app.use(express.json())`, set a size cap to prevent memory-exhaustion DoS.

```js
app.use(express.json({ limit: '100kb' }));
app.use(express.urlencoded({ extended: false, limit: '100kb' }));
```

---

### 9. No error-handling middleware (Low)

Unhandled errors will leak stack traces to clients in some configurations.

**Fix**:

```js
app.use((err, req, res, next) => {
  req.log?.error({ err }, 'unhandled');
  res.status(err.status || 500).json({ error: 'internal_error' });
});
```

Also add `process.on('unhandledRejection' / 'uncaughtException')` handlers that log and exit.

---

### 10. Input validation — preventive note (A03)

There is no user input in this file today, but both endpoints will likely grow. Adopt a schema validator (`zod`, `joi`, or `ajv`) at the boundary rather than hand-rolled checks:

```js
const { z } = require('zod');
const UserQuery = z.object({ limit: z.coerce.number().int().min(1).max(100).default(20) });

app.get('/users', requireAuth, (req, res) => {
  const parsed = UserQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: 'bad_request' });
  // parsed.data.limit is safe to use
});
```

When you move to a database, use parameterized queries/ORM placeholders — never string concatenation — to prevent SQL/NoSQL injection.

---

