const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '100kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => { /* ... */ });

app.use((err, req, res, _next) => {
  req.log?.error({ err });
  res.status(500).json({ error: 'internal_error' });
});

const port = Number(process.env.PORT) || 3000;
const host = process.env.HOST || '127.0.0.1';
app.listen(port, host, () => console.log(`Server on ${host}:${port}`));

module.exports = app;
```

## Things I did *not* find (good news)
- No `eval`, `Function()`, `child_process.exec`, or shell interpolation.
- No SQL/NoSQL queries (no injection surface yet).
- No unsafe deserialization, no `require(userInput)`, no path concatenation on `fs` calls.
- No prototype-pollution sinks (no `Object.assign` onto user input, no recursive merge).

## Recommended next steps
1. Remove `.env.test` from the repo and add `.env*` to `.gitignore`.
2. Add helmet, rate limiting, body-size limit, and a terminal error handler.
3. Put `/users` behind auth before it ever returns real data.
